import{_ as e,o as a,c as l,a7 as i}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"調査行動（Investigation）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/modes/investigation.md","filePath":"ja/modes/investigation.md","lastUpdated":1775394001000}'),n={name:"ja/modes/investigation.md"};function r(d,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="調査行動-investigation" tabindex="-1">調査行動（Investigation） <a class="header-anchor" href="#調査行動-investigation" aria-label="Permalink to &quot;調査行動（Investigation）&quot;">​</a></h1><p><strong>調査行動</strong>は忘却前夜のメインコンテンツであるローグライトモードです。各ランでデッキを構築しながらマップを探索し、最奥のボスを撃破することが目的です。</p><h2 id="基本ルール" tabindex="-1">基本ルール <a class="header-anchor" href="#基本ルール" aria-label="Permalink to &quot;基本ルール&quot;">​</a></h2><ul><li>ランごとに初期デッキからスタート</li><li>道中で<strong>カードの追加・除去・強化</strong>を行いデッキを構築</li><li>マップはランダム生成。戦闘・イベント・ショップ等のノードが配置される</li><li>ラン終了時（クリアまたは敗北）にデッキはリセット</li></ul><h2 id="マップノード" tabindex="-1">マップノード <a class="header-anchor" href="#マップノード" aria-label="Permalink to &quot;マップノード&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">ノード</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;">戦闘</td><td style="text-align:left;">敵との戦闘。勝利でカード・素材報酬</td></tr><tr><td style="text-align:left;">エリートバトル</td><td style="text-align:left;">強敵との戦闘。高報酬</td></tr><tr><td style="text-align:left;">ボス</td><td style="text-align:left;">マップ最奥の強敵。撃破でクリア</td></tr><tr><td style="text-align:left;">イベント</td><td style="text-align:left;">ランダムイベント。選択肢により結果が変化</td></tr><tr><td style="text-align:left;">ショップ</td><td style="text-align:left;">カード購入・除去・強化が可能</td></tr><tr><td style="text-align:left;">休息</td><td style="text-align:left;">HP回復またはカード強化を選択</td></tr><tr><td style="text-align:left;">宝箱</td><td style="text-align:left;">ランダム報酬を入手</td></tr></tbody></table><h2 id="デッキ構築のコツ" tabindex="-1">デッキ構築のコツ <a class="header-anchor" href="#デッキ構築のコツ" aria-label="Permalink to &quot;デッキ構築のコツ&quot;">​</a></h2><ol><li><strong>序盤は攻撃カードを優先</strong> — 戦闘を速く終わらせて被ダメージを抑える</li><li><strong>不要なカードは除去</strong> — デッキが厚いと主力カードが引けない</li><li><strong>シナジーを意識</strong> — カード同士の相性を考えて取得する</li><li><strong>ボス戦を見据える</strong> — 道中だけでなくボス攻略を意識した構築を</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>調査行動のドロップ報酬は密契や育成素材の主要な入手源です。毎日のデイリー消化で必ずプレイしましょう。</p></div><h2 id="難易度" tabindex="-1">難易度 <a class="header-anchor" href="#難易度" aria-label="Permalink to &quot;難易度&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">難易度</th><th style="text-align:left;">解放条件</th><th style="text-align:center;">報酬倍率</th></tr></thead><tbody><tr><td style="text-align:center;"><em>準備中...</em></td><td style="text-align:left;">—</td><td style="text-align:center;">—</td></tr></tbody></table><h2 id="報酬" tabindex="-1">報酬 <a class="header-anchor" href="#報酬" aria-label="Permalink to &quot;報酬&quot;">​</a></h2><p><em>準備中...</em></p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./combat.html">戦闘システム</a></li><li><a href="./../cards/deckbuilding.html">デッキ構築ガイド</a></li><li><a href="./">ゲームモード一覧</a></li><li><a href="./../guides/dailies.html">デイリー攻略</a></li></ul>',15)])])}const x=e(n,[["render",r]]);export{f as __pageData,x as default};
